  schedule_exchange: { id: "schedule_exchange", label: "Schedule Exchange", category: "operations", shortDescription: "Swap the dumpster on an active rental and reset the pickup clock.", guideDescription: "Schedule Exchange lets you swap out a dumpster mid-rental — for example, when a customer fills it early or needs a different size. When you schedule an exchange, the system cancels the currently scheduled pickup, creates a new exchange task in the correct spot in the rental timeline, and automatically schedules a fresh pickup using your tenant's default rental period (set in Settings → Operations). The pickup date is configurable — leave it blank to auto-calculate, or set Override Pickup Date to pick a specific day. The exchange is inserted into the rental's task chain so the lifecycle page keeps showing the full story: delivery → exchange → pickup.", routeOrSurface: "/rentals", tenantOverrideKey: "schedule_exchange", isUserFacing: true, isGuideEligible: true, keywords: ["exchange", "swap", "dumpster", "schedule"] },
  schedule_exchange_description: { id: "schedule_exchange_description", label: "Swap the dumpster on this rental. A new pickup is automatically scheduled based on your tenant's default rental period.", category: "operations", shortDescription: "Modal description for Schedule Exchange.", guideDescription: "", routeOrSurface: "/rentals", tenantOverrideKey: "schedule_exchange_description", isUserFacing: true, isGuideEligible: false, keywords: ["exchange", "description"] },
