  no_available_sizes_hint: { id: "no_available_sizes_hint", label: "Add an active pricing rule to enable exchanges.", category: "operations", shortDescription: "Hint shown when no active sizes are available.", guideDescription: "", routeOrSurface: "/rentals", tenantOverrideKey: "no_available_sizes_hint", isUserFacing: true, isGuideEligible: false, keywords: ["empty", "hint", "pricing"] },
  new_pickup_date: { id: "new_pickup_date", label: "New pickup date", category: "operations", shortDescription: "Auto-calculated pickup date after an exchange.", guideDescription: "After an exchange, the new pickup date is calculated as exchange date + your tenant's default rental period (configurable in Settings → Operations). You can override this with a manual date in the Schedule Exchange modal.", routeOrSurface: "/rentals", tenantOverrideKey: "new_pickup_date", isUserFacing: true, isGuideEligible: true, keywords: ["new", "pickup", "date", "recalculation"] },
  override_pickup_date: { id: "override_pickup_date", label: "Override pickup date (optional)", category: "operations", shortDescription: "Manually override the recalculated pickup date.", guideDescription: "When scheduling an exchange, the system auto-calculates the new pickup date based on your tenant's default rental period. Use Override Pickup Date to choose a different date — handy for promotional extensions or short-term rentals. If left blank, the auto-calculated date is used. The override date must be after the exchange date.", routeOrSurface: "/rentals", tenantOverrideKey: "override_pickup_date", isUserFacing: true, isGuideEligible: true, keywords: ["override", "pickup", "date", "exchange"] },
  override_pickup_date_hint: { id: "override_pickup_date_hint", label: "Leave blank to auto-calculate from your tenant rental period.", category: "operations", shortDescription: "Hint text under override pickup date field.", guideDescription: "", routeOrSurface: "/rentals", tenantOverrideKey: "override_pickup_date_hint", isUserFacing: true, isGuideEligible: false, keywords: ["override", "hint"] },
