  lifecycle_update_error: { id: "lifecycle_update_error", label: "Failed to update lifecycle", category: "operations", shortDescription: "Error state for lifecycle chain updates.", guideDescription: "", routeOrSurface: "/rentals", tenantOverrideKey: "lifecycle_update_error", isUserFacing: true, isGuideEligible: false, keywords: ["error", "lifecycle"] },
  edit_delivery_date: { id: "edit_delivery_date", label: "Edit Delivery Date", category: "operations", shortDescription: "Reschedule the delivery task from the lifecycle page.", guideDescription: "Edit Delivery Date lets you reschedule when the dumpster will be dropped off, straight from the rental lifecycle page. By default, every downstream task (exchanges and the terminal pickup) shifts by the same number of days so the rental duration stays intact — for example, moving delivery from Monday to Wednesday pushes the pickup from Monday two weeks later to Wednesday two weeks later. Uncheck 'Shift downstream dates' to move only the delivery date; the request will fail if any existing downstream task would then sit on or before the new delivery date. Chain integrity, tenant scoping, and job-level `scheduled_date`/`rental_start_date` sync are all handled in a single backend transaction.", routeOrSurface: "/rentals", tenantOverrideKey: "edit_delivery_date", isUserFacing: true, isGuideEligible: true, keywords: ["edit", "delivery", "date", "reschedule"] },
  edit_delivery_date_description: { id: "edit_delivery_date_description", label: "Reschedule the delivery. Downstream tasks shift by the same number of days unless you opt out.", category: "operations", shortDescription: "Modal description for Edit Delivery Date.", guideDescription: "", routeOrSurface: "/rentals", tenantOverrideKey: "edit_delivery_date_description", isUserFacing: true, isGuideEligible: false, keywords: ["edit", "delivery", "description"] },
  edit_exchange_date: { id: "edit_exchange_date", label: "Edit Exchange Date", category: "operations", shortDescription: "Reschedule an existing exchange task from the lifecycle timeline.", guideDescription: "Edit Exchange Date lets you move a scheduled exchange to a different day from the rental lifecycle page. Click the pencil icon on an exchange row in the Connected Tasks timeline to open the modal. The new pickup date is automatically recalculated from your tenant's default rental period (exchange date + default rental days); to pick a specific pickup date instead, set Override Pickup Date in the modal. The system enforces: exchange date cannot be before the delivery date or the previous task, and pickup date must be after the exchange date. Only scheduled exchanges are editable — cancelled or completed exchanges cannot be rescheduled.", routeOrSurface: "/rentals", tenantOverrideKey: "edit_exchange_date", isUserFacing: true, isGuideEligible: true, keywords: ["edit", "exchange", "date", "reschedule"] },
