  replacement_job: { id: "replacement_job", label: "Replacement job", category: "operations", shortDescription: "Generic label for a task that replaces a cancelled job in the chain.", guideDescription: "", routeOrSurface: "job_detail", tenantOverrideKey: "replacement_job", isUserFacing: true, isGuideEligible: false, keywords: ["replacement", "job"] },
  view_replacement_job: { id: "view_replacement_job", label: "View replacement job", category: "operations", shortDescription: "Tooltip/ARIA label for the replacement row link.", guideDescription: "", routeOrSurface: "job_detail", tenantOverrideKey: "view_replacement_job", isUserFacing: true, isGuideEligible: false, keywords: ["view", "replacement"] },
  view_lifecycle: { id: "view_lifecycle", label: "View full lifecycle", category: "operations", shortDescription: "Link from a cancelled job's replacement section to the rental lifecycle page.", guideDescription: "", routeOrSurface: "job_detail", tenantOverrideKey: "view_lifecycle", isUserFacing: true, isGuideEligible: false, keywords: ["lifecycle", "view"] },
  why_jobs_are_cancelled: { id: "why_jobs_are_cancelled", label: "Why Jobs Are Automatically Cancelled", category: "operations", shortDescription: "Explains why and how the system auto-cancels jobs during lifecycle changes.", guideDescription: "Some jobs on your account are cancelled automatically by the system when a lifecycle change makes the original task obsolete. The most common case is an exchange: when you schedule an exchange on an active rental, the currently-scheduled pickup is no longer valid (a new dumpster is going out, and a new pickup is required), so the system cancels the old pickup and inserts a new exchange + new pickup in its place. When you open a cancelled pickup in job detail, you will see (1) a clear reason — 'Cancelled due to exchange replacement' — (2) a 'Replaced by' section listing the chain-derived replacement tasks (the new exchange and the new pickup), each clickable to its job detail page, and (3) a 'View full lifecycle' link that takes you to the rental lifecycle timeline so you can see the full sequence of tasks. Replacement jobs are not guessed — they are read directly from the rental chain's task links, so what you see is always what the system actually scheduled. Legacy jobs that were cancelled before the cancellation-reason field was introduced show a generic fallback label ('Cancelled as part of lifecycle update') and do not fabricate a replacement list. If you manually cancel a job from the job detail page, the reason you typed in the prompt is preserved and displayed here instead of the automated label.", routeOrSurface: "job_detail", tenantOverrideKey: "why_jobs_are_cancelled", isUserFacing: true, isGuideEligible: true, keywords: ["cancelled", "why", "automatic", "exchange", "replacement", "lifecycle"] },
