  help_pricing_structure: { id: "help_pricing_structure", label: "Where Pricing Lives", category: "operations", shortDescription: "The Pricing admin surface is split into a hub page and a dedicated scalable rules view.", guideDescription: "Pricing administration is organized as a hub with four distinct surfaces: (1) the main `/pricing` page is a hub that lists Pricing Rules, Delivery Zones, Surcharge Templates, and Terms & Conditions — it no longer tries to render every pricing rule as a large tile, so it stays scannable for tenants with many rules and future service categories (portable storage, restrooms, equipment rentals); (2) `/pricing/rules` is the dedicated scalable pricing-rules view — a compact table with search that edits rules through the same slide-over form as before; (3) `/pricing/surcharges` manages reusable surcharge templates that get pulled into invoices and quotes; (4) `/pricing/terms` manages the customer-facing legal text attached to quotes and invoices. The pricing logic itself is unchanged — quoting, calculation, delivery-zone math, invoice generation, and the customer-facing invoice descriptions (e.g. '20yd Dumpster Rental') all continue to work exactly as they did before the refactor. Only the admin UI chrome changed — everything downstream of the admin form, including the rule's `name` field which flows into invoices, is preserved so invoice wording stays stable.", routeOrSurface: "/pricing", tenantOverrideKey: "help_pricing_structure", isUserFacing: true, isGuideEligible: true, keywords: ["pricing", "structure", "rules", "hub", "help"] },
  help_customer_dashboard_overview: { id: "help_customer_dashboard_overview", label: "Customer Detail Overview Tab — Command Center Layout", category: "operations", shortDescription: "The customer detail Overview tab surfaces active rentals, service location, and finance snapshot above historical-metric tiles.", guideDescription: "The internal customer detail page Overview tab is organized as a command center. The right column of the Overview grid shows three always-visible cards stacked in operational priority: (1) Active Rentals — lists up to five currently-active jobs for this customer (any job whose status is not completed or cancelled) with clickable rows that jump straight to the job detail, plus an 'All jobs →' link in the card header that drops you into a filtered jobs list. No click is required to see what the customer currently has open. (2) Service Location — displays the customer's primary service address with a prominent ~260px Mapbox map when the address is geocoded. When the address on file has no latitude/longitude, the card still shows the address text plus a clear 'Address on file is not geocoded — map unavailable' hint, instead of silently hiding the map like the old layout did. An empty-state path invites the operator to add a service address through the Edit Customer slide-over. (3) Finance Snapshot — shows the customer's current net balance (outstanding invoices minus active credit memos), a past-due-invoice count in red if any, and the last recorded payment date. A 'View billing →' action jumps to the Billing tab where the full invoice / payment history lives. Below these three cards, the four historical-metric tiles (Jobs, Revenue, Avg Value, Last Job) still drive a drill-down detail panel for operators who want to scan historical activity. The 'Active' tile was removed because its content now lives in the always-visible top card — clicking to see active rentals is no longer required. The left column (Contact, Billing Address, Tags, Notes) is unchanged and keeps the customer's supporting identity information. None of the underlying data fetches changed — every new card is rendered from the same `/customers/:id`, `/jobs?customerId=…`, `/invoices?customerId=…`, and `/invoices/credit-memos/by-customer/:id` responses the page already loaded, so the refactor adds zero network cost.", routeOrSurface: "/customers", tenantOverrideKey: "help_customer_dashboard_overview", isUserFacing: true, isGuideEligible: true, keywords: ["customer", "dashboard", "overview", "active", "rentals", "location", "map", "finance", "billing"] },
  customer_jobs_rental_chains_heading: { id: "customer_jobs_rental_chains_heading", label: "Rental Lifecycles", category: "operations", shortDescription: "Section header on the customer detail Jobs tab for grouped rental lifecycle rows.", guideDescription: "", routeOrSurface: "/customers", tenantOverrideKey: "customer_jobs_rental_chains_heading", isUserFacing: true, isGuideEligible: false, keywords: ["customer", "jobs", "rental", "chains"] },
  customer_jobs_standalone_heading: { id: "customer_jobs_standalone_heading", label: "Standalone Jobs", category: "operations", shortDescription: "Section header on the customer detail Jobs tab for standalone (non-chain) jobs.", guideDescription: "", routeOrSurface: "/customers", tenantOverrideKey: "customer_jobs_standalone_heading", isUserFacing: true, isGuideEligible: false, keywords: ["customer", "jobs", "standalone"] },
  help_grouped_lifecycle_rows: { id: "help_grouped_lifecycle_rows", label: "Grouped Lifecycle Rows on Jobs Surfaces", category: "operations", shortDescription: "Delivery, exchange, and pickup tasks for the same rental are collapsed into a single expandable row.", guideDescription: "Two office surfaces — the main Rental Lifecycles page at `/jobs` and the Jobs tab inside the customer detail page — group related tasks under a single expandable row per rental chain instead of listing delivery, exchange, and pickup as separate flat rows. Each parent row shows the canonical rental summary (size, delivered date, expected pickup, task progress like '2/3', and a derived lifecycle status such as 'Awaiting Pickup' or 'Exchange Scheduled') pulled from the authoritative `rental_chains` + `task_chain_links` data, so there is no second lifecycle engine and no duplicated truth. Clicking anywhere on a parent row toggles the expansion and reveals the child task rows in lifecycle order (delivery → exchange → pickup), each of which remains clickable and navigates straight to its individual job detail page. A small right-arrow action on the parent row jumps to the full `/rentals/:id` lifecycle page for operators who want the deep-dive view. Rows are collapsed by default so the jobs surface stays scannable for customers with many historical rentals. Standalone jobs that are not part of any rental chain continue to render in their own flat table beneath the grouped section; they were never part of a lifecycle so they do not need expansion and the UI never forces them into a fake group. All search, date-range, and job-type-chip filters from the main Jobs page still apply — when a type chip like 'Pickups' is active the chains table is intentionally suppressed and the filter narrows the lower standalone-table to the selected types, because chains by definition mix multiple task types and displaying them alongside a type filter would produce contradictory output.", routeOrSurface: "/jobs", tenantOverrideKey: "help_grouped_lifecycle_rows", isUserFacing: true, isGuideEligible: true, keywords: ["lifecycle", "chain", "group", "expand", "collapse", "jobs", "customer"] },
