  lifecycle_strip: { id: "lifecycle_strip", label: "Lifecycle Strip", category: "operations", shortDescription: "Compact lifecycle summary on the job detail page.", guideDescription: "The Lifecycle Strip appears below the job timeline when the job is part of a rental chain. It shows the delivery date, pickup date, rental duration, and lifecycle status at a glance — so you can answer customer questions without opening the full lifecycle page. Click the strip to navigate to the complete lifecycle view.", routeOrSurface: "job_detail", tenantOverrideKey: "lifecycle_strip", isUserFacing: true, isGuideEligible: true, keywords: ["lifecycle", "strip", "summary", "compact"] },

