  lifecycle_dashboard: { id: "lifecycle_dashboard", label: "Rental Lifecycles", category: "operations", shortDescription: "Lifecycle-first Jobs dashboard.", guideDescription: "The Jobs page now shows rental lifecycles as the primary view. Each row represents one rental chain — delivery through pickup — instead of individual task rows. Click any lifecycle row to open the full lifecycle detail page. Standalone jobs that are not part of a rental chain appear in a separate section below. The Dispatch board remains task-based for driver execution.", routeOrSurface: "/jobs", tenantOverrideKey: "lifecycle_dashboard", isUserFacing: true, isGuideEligible: true, keywords: ["lifecycle", "dashboard", "rentals", "jobs"] },
