  jobs_filtering: { id: "jobs_filtering", label: "Filtering Jobs by Type", category: "operations", shortDescription: "Filter the Jobs dashboard by job type.", guideDescription: "Use the job type filter chips on the Jobs dashboard to narrow your view by Delivery, Pickup, or Exchange. These filters combine with existing status filters — for example, you can view only unassigned deliveries by selecting both the Unassigned status and the Delivery type filter. Multiple type filters can be active at once. When no type filter is selected, all job types are shown.", routeOrSurface: "/jobs", tenantOverrideKey: "jobs_filtering", isUserFacing: true, isGuideEligible: true, keywords: ["filter", "job type", "delivery", "pickup", "exchange"] },
